  1→/**
  2→ * Zweck: Einstiegspunkt für das Landing-Projekt.
  3→ * Rendert ein rundes Pixelraster (weiß) auf schwarzem Hintergrund im Browserfenster.
  4→ */
  5→
  6→import { createToggleButton } from '../../lib.js';
  7→import { createRasterController } from './controller.js';
  8→
  9→const RASTER_PIXEL_SIZE = 6;
 10→const ABOUT_TEXT = [
 11→  'Gnomon Practice is a small collective based in Zurich, Switzerland.',
 12→  'Our work is guided by a search for independence within the systems and technologies we rely on. What begins as curiosity develops into experiments we share.',
 13→].join('\n');
 14→
 15→let cleanup = null;
 16→
 17→function clamp(value, min, max) {
 18→  return Math.min(max, Math.max(min, value));
 19→}
 20→
 21→function createVerticalSlider({
 22→  label,
 23→  min,
 24→  max,
 25→  initialValue,
 26→  onInput,
 27→}) {
 28→  const root = document.createElement('div');
 29→  root.style.position = 'relative';
 30→  root.style.width = '4.8rem';
 31→  root.style.height = '10.5rem';
 32→  root.style.isolation = 'isolate';
 33→  root.style.pointerEvents = 'auto';
 34→
 35→  const text = document.createElement('div');
 36→  text.textContent = label;
 37→  text.style.position = 'absolute';
 38→  text.style.top = '0.1rem';
 39→  text.style.left = '0';
 40→  text.style.width = '100%';
 41→  text.style.textAlign = 'center';
 42→  text.style.fontFamily = '"Helvetica Neue", Helvetica, Arial, sans-serif';
 43→  text.style.fontSize = '0.62rem';
 44→  text.style.fontWeight = '500';
 45→  text.style.lineHeight = '1';
 46→  text.style.textTransform = 'lowercase';
 47→  text.style.color = '#ffffff';
 48→  text.style.mixBlendMode = 'difference';
 49→  text.style.pointerEvents = 'none';
 50→  text.style.display = 'none';
 51→  root.appendChild(text);
 52→
 53→  const track = document.createElement('div');
 54→  track.style.position = 'absolute';
 55→  track.style.left = '50%';
 56→  track.style.top = '1.35rem';
 57→  track.style.bottom = '0.1rem';
 58→  track.style.width = '1rem';
 59→  track.style.transform = 'translateX(-50%)';
 60→  track.style.border = '1px solid #ffffff';
 61→  track.style.background = 'transparent';
 62→  track.style.boxSizing = 'border-box';
 63→  track.style.cursor = 'ns-resize';
 64→  root.appendChild(track);
 65→
 66→  const fill = document.createElement('div');
 67→  fill.style.position = 'absolute';
 68→  fill.style.left = '0';
 69→  fill.style.right = '0';
 70→  fill.style.bottom = '0';
 71→  fill.style.height = '0%';
 72→  fill.style.background = '#ffffff';
 73→  track.appendChild(fill);
 74→
 75→  const handle = document.createElement('div');
 76→  handle.style.position = 'absolute';
 77→  handle.style.left = '50%';
 78→  handle.style.width = '1.2rem';
 79→  handle.style.height = '0.2rem';
 80→  handle.style.border = '1px solid #ffffff';
 81→  handle.style.background = '#ffffff';
 82→  handle.style.transform = 'translate(-50%, 50%)';
 83→  handle.style.bottom = '0%';
 84→  handle.style.boxSizing = 'border-box';
 85→  track.appendChild(handle);
 86→
 87→  let value = clamp(initialValue, min, max);
 88→
 89→  function render() {
 90→    const t = (value - min) / (max - min);
 91→    const pct = clamp(t, 0, 1) * 100;
 92→    fill.style.height = `${pct}%`;
 93→    handle.style.bottom = `${pct}%`;
 94→  }
 95→
 96→  function setValue(nextValue, emit = true) {
 97→    value = clamp(nextValue, min, max);
 98→    render();
 99→    if (emit) {
100→      onInput(value);
101→    }
102→  }
103→
104→  function valueFromPointer(clientY) {
105→    const rect = track.getBoundingClientRect();
106→    const t = clamp((rect.bottom - clientY) / rect.height, 0, 1);
107→    return min + (max - min) * t;
108→  }
109→
110→  function handlePointerMove(event) {
111→    setValue(valueFromPointer(event.clientY));
112→  }
113→
114→  function handlePointerUp() {
115→    window.removeEventListener('pointermove', handlePointerMove);
116→    window.removeEventListener('pointerup', handlePointerUp);
117→  }
118→
119→  function handlePointerDown(event) {
120→    event.preventDefault();
121→    setValue(valueFromPointer(event.clientY));
122→    window.addEventListener('pointermove', handlePointerMove);
123→    window.addEventListener('pointerup', handlePointerUp);
124→  }
125→
126→  track.addEventListener('pointerdown', handlePointerDown);
127→  render();
128→
129→  return {
130→    element: root,
131→    setValue(nextValue) {
132→      setValue(nextValue, false);
133→    },
134→    destroy() {
135→      track.removeEventListener('pointerdown', handlePointerDown);
136→      window.removeEventListener('pointermove', handlePointerMove);
137→      window.removeEventListener('pointerup', handlePointerUp);
138→    },
139→  };
140→}
