  1→/**
  2→ * Zweck: Steuerung des Pixelrasters im Canvas.
  3→ * Hält den Zustand und führt iterative Updates für die Animation aus.
  4→ */
  5→
  6→const DOT_GAP = 0;
  7→const DEBUG_VEC = false;
  8→const TWO_PI = Math.PI * 2;
  9→
 10→export function createRasterController({ canvas, pixelSize }) {
 11→  const ctx = canvas.getContext('2d');
 12→  if (!ctx) {
 13→    throw new Error('2D context unavailable.');
 14→  }
 15→
 16→  const dotSize = Math.max(1, Number(pixelSize) || 1);
 17→  const cell = dotSize + DOT_GAP;
 18→  const radius = Math.max(1, dotSize * 0.35);
 19→
 20→  // --- PARAMETERS ---
 21→  let dir = { x: 1, y: 0.5 };
 22→  let noiseInf = 0.2;
 23→  let turb = 0.01;
 24→  const smooth = 1.0;
 25→  let windStrength = 600;
 26→  const coherenceFactor = 0.5;
 27→  const noiseScale = 0.05;
 28→  let transfer = 0.003;
 29→  let pixelSmooth = 0.1;
 30→  const vecOff = 0.5 * cell;
 31→  const vecStep = 14 * cell;
 32→  const vecLen = 10 * cell;
 33→
 34→  let width = 0;
 35→  let height = 0;
 36→  let cols = 0;
 37→  let rows = 0;
 38→  let pixels = [];
 39→  let vecGrid = [];
 40→  let vecCols = 0;
 41→  let vecRows = 0;
 42→  let gridW = 0;
 43→  let gridH = 0;
 44→  let isRunning = false;
 45→  let animationFrameId = null;
 46→  let simTime = 0;
 47→
 48→  function fade(t) {
 49→    return t * t * (3 - 2 * t);
 50→  }
 51→
 52→  function lerp(a, b, t) {
 53→    return a + (b - a) * t;
 54→  }
 55→
 56→  function hash3(ix, iy, iz) {
 57→    const s = Math.sin(ix * 127.1 + iy * 311.7 + iz * 74.7) * 43758.5453123;
 58→    return s - Math.floor(s);
 59→  }
 60→
 61→  function noise3(x, y, z) {
 62→    const x0 = Math.floor(x);
 63→    const y0 = Math.floor(y);
 64→    const z0 = Math.floor(z);
 65→    const x1 = x0 + 1;
 66→    const y1 = y0 + 1;
 67→    const z1 = z0 + 1;
 68→
 69→    const tx = fade(x - x0);
 70→    const ty = fade(y - y0);
 71→    const tz = fade(z - z0);
 72→
 73→    const n000 = hash3(x0, y0, z0);
 74→    const n100 = hash3(x1, y0, z0);
 75→    const n010 = hash3(x0, y1, z0);
 76→    const n110 = hash3(x1, y1, z0);
 77→    const n001 = hash3(x0, y0, z1);
 78→    const n101 = hash3(x1, y0, z1);
 79→    const n011 = hash3(x0, y1, z1);
 80→    const n111 = hash3(x1, y1, z1);
 81→
 82→    const nx00 = lerp(n000, n100, tx);
 83→    const nx10 = lerp(n010, n110, tx);
 84→    const nx01 = lerp(n001, n101, tx);
 85→    const nx11 = lerp(n011, n111, tx);
 86→    const nxy0 = lerp(nx00, nx10, ty);
 87→    const nxy1 = lerp(nx01, nx11, ty);
 88→    return lerp(nxy0, nxy1, tz);
 89→  }
 90→
 91→  function buildPixelField() {
 92→    pixels = [];
 93→    cols = Math.ceil(width / cell);
 94→    rows = Math.ceil(height / cell);
 95→
 96→    for (let r = 0; r < rows; r += 1) {
 97→      const y = r * cell;
 98→      for (let c = 0; c < cols; c += 1) {
 99→        const x = c * cell;
100→        pixels.push({
101→          x,
102→          y,
103→          h: 0.1 + Math.random() * 0.8,
104→        });
105→      }
106→    }
107→  }
108→
109→  function buildVecGrid() {
110→    vecGrid = [];
111→    const ledMaxX = cols * cell;
112→    const ledMaxY = rows * cell;
113→    const maxNeedX = ledMaxX + vecOff;
114→    const maxNeedY = ledMaxY + vecOff;
115→
116→    const xs = [];
117→    let vx = -vecOff;
118→    while (vx < maxNeedX) {
119→      xs.push(vx);
120→      vx += vecStep;
121→    }
122→    xs.push(maxNeedX);
123→
124→    const ys = [];
125→    let vy = -vecOff;
126→    while (vy < maxNeedY) {
127→      ys.push(vy);
128→      vy += vecStep;
129→    }
130→    ys.push(maxNeedY);
131→
132→    for (let yi = 0; yi < ys.length; yi += 1) {
133→      const vy = ys[yi];
134→      for (let xi = 0; xi < xs.length; xi += 1) {
135→        const vx = xs[xi];
136→        vecGrid.push({
137→          x: vx,
138→          y: vy,
139→          dir: { x: dir.x * windStrength, y: dir.y * windStrength },
140→        });
141→      }
142→    }
143→    vecCols = xs.length;
144→    vecRows = ys.length;
145→    gridW = Math.max(1, vecCols - 1);
146→    gridH = Math.max(1, vecRows - 1);
147→
148→    if (DEBUG_VEC && vecGrid.length > 0) {
149→      const sampleX = xs.filter((x) => x >= vecOff).slice(0, 3).map((x) => x / cell);
150→      const sampleY = ys.filter((y) => y >= vecOff).slice(0, 3).map((y) => y / cell);
151→
152→      const hasHalf = (value) => {
153→        const frac = value % 1;
154→        return Math.abs(frac - 0.5) < 1e-9 || Math.abs(frac + 0.5) < 1e-9;
155→      };
156→
157→      const sampleOk = sampleX.every(hasHalf) && sampleY.every(hasHalf);
158→      const minX = xs[0];
159→      const minY = ys[0];
160→      const maxX = xs[xs.length - 1];
161→      const maxY = ys[ys.length - 1];
162→      const boundsOk = (
163→        minX <= -vecOff &&
164→        minY <= -vecOff &&
165→        maxX >= ledMaxX + vecOff &&
166→        maxY >= ledMaxY + vecOff
167→      );
168→
169→      console.log('[vec] sample x/cell:', sampleX, 'y/cell:', sampleY, 'allHalf:', sampleOk);
170→      console.log('[vec] bounds:', {
171→        minX,
172→        minY,
173→        maxX,
174→        maxY,
175→        ledMinX: 0,
176→        ledMinY: 0,
177→        ledMaxX,
178→        ledMaxY,
179→        minNeededX: -vecOff,
180→        minNeededY: -vecOff,
181→        maxNeededX: ledMaxX + vecOff,
182→        maxNeededY: ledMaxY + vecOff,
183→        extendsOutside: boundsOk,
184→      });
185→    }
186→  }
187→
188→  function draw() {
189→    ctx.fillStyle = '#000000';
190→    ctx.fillRect(0, 0, width, height);
191→
192→    for (let index = 0; index < pixels.length; index += 1) {
193→      const pixel = pixels[index];
194→      const h = Math.max(0, Math.min(1, pixel.h));
195→      const g = Math.round(h * 255);
196→      ctx.fillStyle = `rgb(${g}, ${g}, ${g})`;
197→      ctx.beginPath();
198→      ctx.arc(pixel.x, pixel.y, radius, 0, Math.PI * 2);
199→      ctx.fill();
200→    }
201→
202→    if (DEBUG_VEC) {
203→      ctx.strokeStyle = '#00ffff';
204→      for (let index = 0; index < vecGrid.length; index += 1) {
205→        const vec = vecGrid[index];
206→        ctx.beginPath();
207→        ctx.moveTo(vec.x, vec.y);
208→        ctx.lineTo(vec.x + vec.dir.x * vecLen, vec.y + vec.dir.y * vecLen);
209→        ctx.stroke();
210→      }
211→    }
212→  }
213→
214→  function wrapI(i, n) {
215→    return (i % n + n) % n;
216→  }
217→
218→  function sampleVec(x, y) {
219→    const fx = (x + vecOff) / vecStep;
220→    const fy = (y + vecOff) / vecStep;
221→    const ix0f = Math.floor(fx);
222→    const iy0f = Math.floor(fy);
223→    const tx = fx - ix0f;
224→    const ty = fy - iy0f;
225→    const ix0 = wrapI(ix0f, gridW);
226→    const iy0 = wrapI(iy0f, gridH);
227→    const ix1 = (ix0 + 1) % gridW;
228→    const iy1 = (iy0 + 1) % gridH;
229→
230→    const v00 = vecGrid[iy0 * vecCols + ix0].dir;
231→    const v10 = vecGrid[iy0 * vecCols + ix1].dir;
232→    const v01 = vecGrid[iy1 * vecCols + ix0].dir;
233→    const v11 = vecGrid[iy1 * vecCols + ix1].dir;
234→
235→    const vx0 = v00.x + (v10.x - v00.x) * tx;
236→    const vx1 = v01.x + (v11.x - v01.x) * tx;
237→    const vy0 = v00.y + (v10.y - v00.y) * tx;
238→    const vy1 = v01.y + (v11.y - v01.y) * tx;
239→
240→    return {
241→      x: vx0 + (vx1 - vx0) * ty,
242→      y: vy0 + (vy1 - vy0) * ty,
243→    };
244→  }
245→
246→  function stepLed() {
247→    const curr = pixels;
248→    const vBuf = new Array(curr.length);
249→    const qBuf = new Array(curr.length);
250→    const tBuf = new Array(curr.length);
251→
252→    // PHASE 1 — local vectors
253→    for (let y = 0; y < rows; y += 1) {
254→      for (let x = 0; x < cols; x += 1) {
255→        const i = y * cols + x;
256→        const px = x * cell;
257→        const py = y * cell;
258→        vBuf[i] = sampleVec(px, py);
259→      }
260→    }
261→
262→    // PHASE 2 — transfer amount
263→    for (let i = 0; i < curr.length; i += 1) {
264→      qBuf[i] = transfer * curr[i].h;
265→    }
266→
267→    // PHASE 3 — landing positions
268→    for (let y = 0; y < rows; y += 1) {
269→      for (let x = 0; x < cols; x += 1) {
270→        const i = y * cols + x;
271→        const px = x * cell;
272→        const py = y * cell;
273→        const hPrev = curr[i].h;
274→        const v = vBuf[i];
275→        const m = Math.hypot(v.x, v.y);
276→        const nx = m ? v.x / m : 0;
277→        const ny = m ? v.y / m : 0;
278→        const L = m + transfer * hPrev;
279→        const tx = px + nx * L;
280→        const ty = py + ny * L;
281→        const tc = wrapI(Math.round(tx / cell), cols);
282→        const tr = wrapI(Math.round(ty / cell), rows);
283→        tBuf[i] = tr * cols + tc;
284→      }
285→    }
286→
287→    // PHASE 4 — apply transfers
288→    const next = new Array(curr.length);
289→    for (let i = 0; i < curr.length; i += 1) {
290→      const p = curr[i];
291→      next[i] = { x: p.x, y: p.y, h: p.h };
292→    }
293→    for (let i = 0; i < curr.length; i += 1) {
294→      const q = qBuf[i];
295→      next[i].h -= q;
296→      next[tBuf[i]].h += q;
297→    }
298→
299→    // PHASE 4.5 — pixel smoothing
300→    const sBuf = new Array(curr.length);
301→    for (let y = 0; y < rows; y += 1) {
302→      for (let x = 0; x < cols; x += 1) {
303→        const i = y * cols + x;
304→        const l = y * cols + wrapI(x - 1, cols);
305→        const r = y * cols + wrapI(x + 1, cols);
306→        const u = wrapI(y - 1, rows) * cols + x;
307→        const d = wrapI(y + 1, rows) * cols + x;
308→        const hSelf = next[i].h;
309→        const hMean = (next[l].h + next[r].h + next[u].h + next[d].h) * 0.25;
310→        sBuf[i] = (1 - pixelSmooth) * hSelf + pixelSmooth * hMean;
311→      }
312→    }
313→    for (let i = 0; i < curr.length; i += 1) {
314→      next[i].h = sBuf[i];
315→    }
316→
317→    // PHASE 5 — finalize
318→    pixels = next;
319→  }
320→
321→  function stepSim() {
322→    simTime += turb;
323→
324→    const next = new Array(vecGrid.length);
325→
326→    for (let yi = 1; yi < vecRows - 1; yi += 1) {
