:root {
  --font-w-min: 400px;
  --font-w-max: 1400px;
  --font-sigmoid-steepness: 1;
  --font-scale-factor: 0;

  --title-base: 6vw;
  --title-min: 2rem;
  --title-max: 4rem;
  --title-size: clamp(
    var(--title-min),
    calc(var(--title-base) * (0.5 + (0.5 * var(--font-scale-factor)))),
    var(--title-max)
  );

  --secondary-ratio: 0.5;
  --secondary-text-size: calc(var(--title-size) * var(--secondary-ratio));
}

html,
body,
#app {
  width: 100%;
  height: 100%;
  margin: 0;
}

body {
  overflow: hidden;
}

